def skapa_matris(rader, kolumner):
  matris = []
  for i in range(rader):
    ny_rad = []
    for j in range(kolumner):
      tal = int(input("Ange siffran på rad " + str(i+1) + " kolumn "+ str(j+1) + " : "))
      ny_rad.append(tal)
    matris.append(ny_rad)
  return matris

def utskrift_matris(matris):
  print("Fin utskrift av matrisen: ")
  for rad in matris:
    for element in rad:
      print(element, end= " ")
    print()

def plocka_ut_element(matris):
  rad_index = int(input("På vilken rad? "))
  kolumn_index = int(input("Vilken kolumn? "))
  print("På rad", rad_index, "och kolumn", kolumn_index, "finns ", matris[rad_index][kolumn_index])

def inmatning():
  antal_rader = int(input("Hur många rader vill du ha?: "))
  antal_kolumner = int(input("Hur många kolumner vill du ha?: "))
  return antal_rader, antal_kolumner

def huvudfunktion():
	rader, kolumner = inmatning()
	matrisen = skapa_matris(rader, kolumner)
	print(matrisen)
	utskrift_matris(matrisen)
	plocka_ut_element(matrisen)

huvudfunktion()
